import{_ as t,C as n,o as a,c as r,a0 as o,b as c,w as s,a as d,E as l,a1 as p}from"./chunks/framework.DZNqfkJl.js";const C=JSON.parse('{"title":"Configuración y Arquitectura del Backend","description":"","frontmatter":{},"headers":[],"relativePath":"developer/backend.md","filePath":"developer/backend.md"}'),u={name:"developer/backend.md"};function h(g,e,m,b,k,v){const i=n("Mermaid");return a(),r("div",null,[e[1]||(e[1]=o('<h1 id="configuracion-y-arquitectura-del-backend" tabindex="-1">Configuración y Arquitectura del Backend <a class="header-anchor" href="#configuracion-y-arquitectura-del-backend" aria-label="Permalink to &quot;Configuración y Arquitectura del Backend&quot;">​</a></h1><p>El backend de <strong>Structo</strong> está desarrollado en <strong>.NET 10</strong> utilizando C#. Sigue los principios de la <strong>Arquitectura Limpia (Clean Architecture)</strong> y <strong>N-Capas</strong> para asegurar un código mantenible, testeable y desligado de las tecnologías externas.</p><h2 id="🚀-como-levantar-el-entorno-local" tabindex="-1">🚀 Cómo levantar el entorno local <a class="header-anchor" href="#🚀-como-levantar-el-entorno-local" aria-label="Permalink to &quot;🚀 Cómo levantar el entorno local&quot;">​</a></h2><h3 id="_1-preparacion-de-base-de-datos" tabindex="-1">1. Preparación de Base de Datos <a class="header-anchor" href="#_1-preparacion-de-base-de-datos" aria-label="Permalink to &quot;1. Preparación de Base de Datos&quot;">​</a></h3><p>Asegúrate de tener corriendo tus bases de datos (SQL Server y MongoDB). Puedes levantar los contenedores usando el archivo <code>docker-compose.yml</code> (si dispones de él en la raíz o carpeta <code>docker/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>O usar tus instancias locales. Asegúrate de configurar las cadenas de conexión correctas en los archivos <code>appsettings.Development.json</code> dentro del proyecto principal.</p><h3 id="_2-ejecutar-migraciones-entity-framework" tabindex="-1">2. Ejecutar Migraciones (Entity Framework) <a class="header-anchor" href="#_2-ejecutar-migraciones-entity-framework" aria-label="Permalink to &quot;2. Ejecutar Migraciones (Entity Framework)&quot;">​</a></h3><p>Entra al proyecto backend. Puedes aplicar las migraciones a la base de datos SQL Server de dos maneras:</p><ul><li><strong>Opción 1: Usando los scripts (Recomendado)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./ef.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div></li><li><strong>Opción 2: Usando <code>dotnet</code> tradicional</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> database</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.Infrastructure/Structo.Infrastructure.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><h3 id="_3-cargar-datos-iniciales-seed" tabindex="-1">3. Cargar Datos Iniciales (Seed) <a class="header-anchor" href="#_3-cargar-datos-iniciales-seed" aria-label="Permalink to &quot;3. Cargar Datos Iniciales (Seed)&quot;">​</a></h3><p>El proyecto backend está configurado para ejecutar el proceso de <em>Seeding</em> de datos de forma <strong>automática</strong> cada vez que se levanta la aplicación. Durante el arranque (<code>Program.cs</code>), si existen entidades base faltantes, el sistema las insertará por su cuenta usando <code>InitDatabase</code>.</p><p>Por lo tanto, simplemente arrancar la aplicación efectuará este proceso de <em>seeding</em>:</p><ul><li><strong>Opción 1: Usando el script <code>dev.sh</code> (Recomendado)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./dev.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div></li><li><strong>Opción 2: Usando <code>dotnet</code> tradicional</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><h3 id="_4-correr-el-proyecto" tabindex="-1">4. Correr el Proyecto <a class="header-anchor" href="#_4-correr-el-proyecto" aria-label="Permalink to &quot;4. Correr el Proyecto&quot;">​</a></h3><p>Al igual que las migraciones, tienes dos alternativas para levantar la Web API:</p><ul><li><strong>Opción 1: Usando los scripts (Recomendado)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./dev.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div></li><li><strong>Opción 2: Usando <code>dotnet</code> tradicional</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><p>El servidor de desarrollo iniciará y deberías poder acceder a la interfaz interactiva de la API (Swagger) navegando a:</p><ul><li><code>http://localhost:5000/swagger</code> o</li><li><code>https://localhost:5001/swagger</code> (si usaste el comando de <code>dev.sh run</code> con perfil HTTPS activo).</li></ul><hr><h2 id="🛠️-listado-de-comandos-de-ayuda-scripts-automaticos" tabindex="-1">🛠️ Listado de Comandos de Ayuda (Scripts Automáticos) <a class="header-anchor" href="#🛠️-listado-de-comandos-de-ayuda-scripts-automaticos" aria-label="Permalink to &quot;🛠️ Listado de Comandos de Ayuda (Scripts Automáticos)&quot;">​</a></h2><p>Para facilitar el flujo, el repositorio expone dos scripts <code>.sh</code> en la raíz del backend:</p><h3 id="script-dev-sh" tabindex="-1">Script <code>dev.sh</code> <a class="header-anchor" href="#script-dev-sh" aria-label="Permalink to &quot;Script `dev.sh`&quot;">​</a></h3><p>Envuelve la interfaz de línea de comandos de .NET agregando la configuración por defecto y el perfil HTTPS.</p><ul><li><code>./dev.sh run</code>: Ejecuta la aplicación con el perfil HTTPS.</li><li><code>./dev.sh watch</code>: Ejecuta la aplicación con Hot Reload (watch) habilitado.</li><li><code>./dev.sh build</code>: Compila la solución completa.</li><li><code>./dev.sh build-errors</code>: Compila mostrando únicamente los errores de compilación.</li><li><code>./dev.sh test</code>: Ejecuta todos los tests automáticos encontrados (Unidad e Integración).</li><li><code>./dev.sh clean</code>: Limpia la solución compilada.</li><li><code>./dev.sh restore</code>: Restaura todos los paquetes NuGet.</li></ul><h3 id="script-ef-sh" tabindex="-1">Script <code>ef.sh</code> <a class="header-anchor" href="#script-ef-sh" aria-label="Permalink to &quot;Script `ef.sh`&quot;">​</a></h3><p>Envuelve <code>dotnet ef</code> pre-estableciendo los nombres correctos de los proyectos de Infraestructura y WebApi.</p><ul><li><code>./ef.sh add &lt;nombre&gt;</code>: Añade una nueva migración.</li><li><code>./ef.sh update</code>: Aplica las migraciones pendientes en la base de datos.</li><li><code>./ef.sh remove</code>: Revierte y elimina la última migración.</li><li><code>./ef.sh list</code>: Lista todas las migraciones existentes.</li></ul><hr><h2 id="🏗️-patrones-de-diseno-utilizados" tabindex="-1">🏗️ Patrones de Diseño Utilizados <a class="header-anchor" href="#🏗️-patrones-de-diseno-utilizados" aria-label="Permalink to &quot;🏗️ Patrones de Diseño Utilizados&quot;">​</a></h2><p>Durante el desarrollo del backend, se promueve el uso de los siguientes patrones arquitectónicos:</p><ul><li><strong>Inyección de Dependencias (DI)</strong>: Utilizado orgánicamente en .NET Core para inyectar servicios en controladores y otros servicios, promoviendo el bajo acoplamiento.</li><li><strong>Repository Pattern</strong>: Abstracción de acceso a datos provista por las interfaces en el <code>Domain</code> y su implementación en la capa de <code>Infrastructure</code>.</li><li><strong>Data Transfer Objects (DTO)</strong>: Aislando completamente la capa de controladores y los modelos de dominio.</li><li><strong>CQRS (Opcional, según complejidad)</strong>: Separación ligera entre lectura y mutación manejada en la capa de servicios.</li></ul><h2 id="📁-estructura-de-proyectos-n-capas" tabindex="-1">📁 Estructura de Proyectos (N-Capas) <a class="header-anchor" href="#📁-estructura-de-proyectos-n-capas" aria-label="Permalink to &quot;📁 Estructura de Proyectos (N-Capas)&quot;">​</a></h2><p>La solución (<code>Structo.sln</code>) y el directorio <code>src/</code> están divididos conceptualmente:</p>',34)),(a(),c(p,null,{default:s(()=>[l(i,{id:"mermaid-210",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20API%5BStructo.WebApi%5CnCapa%20de%20Presentaci%C3%B3n%5D%20--%3E%20S%5BStructo.Services%5CnL%C3%B3gica%20de%20Aplicaci%C3%B3n%5D%0A%20%20%20%20API%20--%3E%20DTO%5BStructo.DTO%5CnContratos%20de%20Datos%5D%0A%20%20%20%20S%20--%3E%20DOM%5BStructo.Domain%5CnReglas%20de%20Negocio%20%2F%20Entidades%5D%0A%20%20%20%20S%20--%3E%20INF%5BStructo.Infrastructure%5CnAcceso%20a%20Datos%20%2F%20EF%20Core%5D%0A%20%20%20%20INF%20--%3E%20DOM%0A%20%20%20%20API%20-.%20Inyecta%20.-%3E%20INF%0A%20%20%20%20%0A%20%20%20%20style%20API%20fill%3A%232a70d9%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20S%20fill%3A%230b8a4f%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20INF%20fill%3A%23d9702a%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h3 id="descripcion-de-las-capas" tabindex="-1">Descripción de las Capas <a class="header-anchor" href="#descripcion-de-las-capas" aria-label="Permalink to &quot;Descripción de las Capas&quot;">​</a></h3><ol><li><strong>Structo.WebApi</strong>: Contiene los Controladores (Endpoints HTTP), la configuración del host y el registro de la inyección de dependencias (<code>Program.cs</code>). Responsable de recibir las consultas y delvolver DTOs.</li><li><strong>Structo.Services</strong>: Contiene la lógica de aplicación. Coordina cómo la aplicación interactúa con la base de datos a través de las interfaces y aplica reglas de negocio a gran escala, orquestando mapeos entre Entidades de Dominio y DTOs.</li><li><strong>Structo.Domain</strong>: Es el núcleo del sistema. Contiene las Entidades (modelos de tabla), Enums, Interfaces core y lógica de negocio pura de forma estricta. <strong>No depende de ningún otro proyecto de la solución</strong>.</li><li><strong>Structo.Infrastructure</strong>: Contiene las clases de <code>DbContext</code> (Entity Framework), las implementaciones reales de los repositorios y la configuración hacia bases de datos externas (SQL Server / MongoDB). Depende de <code>Structo.Domain</code>.</li><li><strong>Structo.DTO</strong>: Contiene estructuras planas que transportan los datos solicitados hacia el exterior de la API, evitando exponer directamente las clases del Dominio.</li><li><strong>Structo.Common</strong>: Constantes transversales, excepciones personalizadas compartidas y métodos de extensión para toda la solución.</li></ol><hr><h2 id="📐-convenciones-de-nombrado-y-dtos" tabindex="-1">📐 Convenciones de Nombrado y DTOs <a class="header-anchor" href="#📐-convenciones-de-nombrado-y-dtos" aria-label="Permalink to &quot;📐 Convenciones de Nombrado y DTOs&quot;">​</a></h2><p>Al transportar datos, la aplicación obliga a separar la capa de Dominio de la capa HTTP usando <strong>DTOs (Data Transfer Objects)</strong>. Estos se ubican en <code>src/Structo.DTO/Models</code>. Para mantener la consistencia, usa los siguientes prefijos o sufijos:</p><ul><li><code>*Model</code>: Para representar una entidad de salida o de vista general (ej. <code>OrderModel</code>).</li><li><code>Create*RequestModel</code> / <code>Create*Model</code>: Payload requerido para un endpoint <code>POST</code> (ej. <code>CreateOrderRequestModel</code>).</li><li><code>Update*RequestModel</code> / <code>Update*Model</code>: Payload para actualizar una entidad en un endpoint <code>PUT</code>.</li><li><code>*FilterModel</code> / <code>*Request</code>: Usado típicamente para recibir parámetros de búsqueda o paginación.</li></ul><p><em>Nota: La validación de los DTOs de entrada se realiza con <code>FluentValidation</code> en el directorio <code>Structo.DTO/FluentValidations/</code> antes de tocar los controladores.</em></p><hr><h2 id="🔐-autenticacion-y-autorizacion-identity" tabindex="-1">🔐 Autenticación y Autorización (Identity) <a class="header-anchor" href="#🔐-autenticacion-y-autorizacion-identity" aria-label="Permalink to &quot;🔐 Autenticación y Autorización (Identity)&quot;">​</a></h2><p>El sistema utiliza <strong>ASP.NET Core Identity</strong> con tokens <strong>JWT</strong> para manejar usuarios, roles y autenticación.</p><ul><li><strong>Roles:</strong> El modelo de BD posee roles predefinidos (<code>SuperAdmin</code>, <code>Admin</code>, etc.).</li><li><strong>Permisos Específicos (Claims):</strong> Además de roles, el control fino se hace mediante <code>IdentityRoleClaim</code>. Por ejemplo, en el seed pudimos ver claims como <code>list:roles</code>, <code>edit:roles</code>. En los controladores, puedes usar la política/autorización basada en estos claims para restringir el acceso a ciertos endpoints.</li></ul><hr><h2 id="🏗️-flujo-de-creacion-de-una-nueva-entidad" tabindex="-1">🏗️ Flujo de Creación de una Nueva Entidad <a class="header-anchor" href="#🏗️-flujo-de-creacion-de-una-nueva-entidad" aria-label="Permalink to &quot;🏗️ Flujo de Creación de una Nueva Entidad&quot;">​</a></h2><p>Si necesitas agregar una tabla/funcionalidad completamente nueva al sistema (ej. <code>Invoice</code>), sigue esta secuencia estricta:</p><ol><li><strong>Domain</strong>: Crea la entidad <code>Invoice.cs</code> dentro de <code>src/Structo.Domain/Entities/</code>. Hereda de base entities si aplica.</li><li><strong>Infrastructure (DB)</strong>: Agrega el <code>DbSet&lt;Invoice&gt; Invoices { get; set; }</code> en <code>AppDbContext.cs</code>.</li><li><strong>Migración</strong>: Ejecuta <code>./ef.sh add AddInvoiceTable</code> seguido de <code>./ef.sh update</code> para actualizar la base de datos local.</li><li><strong>DTO y Validaciones</strong>: Crea <code>InvoiceModel</code> y <code>CreateInvoiceModel</code> en <code>Structo.DTO</code>, y de ser necesario, un validador en <code>FluentValidations</code>.</li><li><strong>Services</strong>: Crea <code>IInvoiceService</code> e <code>InvoiceService</code> en <code>Structo.Services/</code>. Aplica ahí tu lógica de negocio y registra el servicio en <code>ServicesInjection.cs</code>.</li><li><strong>WebApi</strong>: Expone el controlador <code>InvoicesController.cs</code> inyectando el servicio.</li></ol><hr><h2 id="⚙️-tareas-background-y-notificaciones" tabindex="-1">⚙️ Tareas Background y Notificaciones <a class="header-anchor" href="#⚙️-tareas-background-y-notificaciones" aria-label="Permalink to &quot;⚙️ Tareas Background y Notificaciones&quot;">​</a></h2><p>En <code>Program.cs</code> se inicializan herramientas clave para la comunicación asíncrona:</p><ul><li><strong>Quartz.NET</strong>: Para tareas cronometradas (Scheduled Jobs). Si quieres que algo se corra todos los días a media noche, crea un Job de Quartz.</li><li><strong>TickerQ</strong>: Usado como una cola simple de tareas en memoria, principalmente para encolar trabajo transaccional/ligero y sacarlo del hilo HTTP principal.</li><li><strong>SignalR (WebSockets)</strong>: Configuraciones expuestas en los hubs <code>/hubs/tasks</code> o <code>/hubs/notifications</code> para empujar notificaciones en tiempo real al frontend Vue/Nuxt.</li><li><strong>Notificaciones Externas</strong>: La inyección de dependencias ya contempla clientes para Twilio (<code>ITwilioRestClient</code>) para WhatsApp/SMS y el ecosistema Facebook (<code>WhatsAppHttpClient</code>). Puedes inyectar estos servicios donde lo requieras.</li></ul>',19))])}const f=t(u,[["render",h]]);export{C as __pageData,f as default};
